import{_ as r,c as l,o,ak as t}from"./chunks/framework.CYxz2ou1.js";const c=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"NanoMind/C-工作/3-2025面试/13-非技术问题.md","filePath":"NanoMind/C-工作/3-2025面试/13-非技术问题.md","lastUpdated":1775490538000}'),i={name:"NanoMind/C-工作/3-2025面试/13-非技术问题.md"};function n(e,a,s,h,d,g){return o(),l("div",null,[...a[0]||(a[0]=[t('<h3 id="离职的原因" tabindex="-1">离职的原因 <a class="header-anchor" href="#离职的原因" aria-label="Permalink to &quot;离职的原因&quot;">​</a></h3><ul><li><strong>成长空间有限。技术能力和晋升的提升空间都有限</strong>。这几年业务发展还不错，领导层都比较固化，职级上几年只变过一次领导，<strong>晋升通路不是很顺畅</strong>。</li><li><strong>技术上，架构能力</strong>想要更多的锻炼，<strong>想到一个大的平台去见识和学习</strong>。</li><li>离家人更近一些。</li></ul><h3 id="对自己的未来发展有什么想法和计划" tabindex="-1">对自己的未来发展有什么想法和计划 <a class="header-anchor" href="#对自己的未来发展有什么想法和计划" aria-label="Permalink to &quot;对自己的未来发展有什么想法和计划&quot;">​</a></h3><ul><li><strong>技术</strong>：目前我的技术水平还处于高级开发的阶段，计划是在 2 年内达到一个技术专家的水平，我希望我在<strong>某个领域可以做到比较擅长</strong>。这个过程中我知道会需要付出很多努力，但是我愿意承担更多的挑战，让自己的技术水平可以不断提升。</li><li><strong>业务</strong>：我希望自己在接下来的 2-3 年可以在 XX 业务领域上深入理解，深耕成为一个业务领域专家，让自己在技术上不仅可以有所建树，也能在业务方面有自己的理解。不仅作为一个开发者，还能在业务方面有一些自己的想法，并且可以赋能我们的业务。</li><li><strong>架构&amp;管理</strong>：我希望在接下来几年，锻炼一下自己的<strong>架构和管理能力</strong>，我希望在公司的技术团队中成长，不断学习和探索新技术，并在技术架构和团队管理方面获得更多的经验。并能够贡献我的技术和经验帮助公司取得更大的成功。</li></ul><h3 id="自己的缺点" tabindex="-1">自己的缺点 <a class="header-anchor" href="#自己的缺点" aria-label="Permalink to &quot;自己的缺点&quot;">​</a></h3><ul><li>在遇到自己不熟悉的事情的时候比较容易紧张。</li><li>演讲能力有待提升，比如超过 10 人的团队做演讲时比较罗嗦。</li><li>刚开始工作的时候，有时候容易陷入历史的逻辑中，容易在原有的基础上去设计优化。后面跟架构师的学习当中，需要站在全局去看，然后每次都会找同事先过一下方案。现在思维好些了，所以也想跳出来看看更好的架构设计是怎么样的。</li></ul><h3 id="自己的优点" tabindex="-1">自己的优点 <a class="header-anchor" href="#自己的优点" aria-label="Permalink to &quot;自己的优点&quot;">​</a></h3><ul><li>负责和韧劲。比较踏实认真。</li><li>乐于沟通。</li><li>会发掘效率工具，平时喜欢提效。</li></ul><h3 id="最近学习的新技术" tabindex="-1">最近学习的新技术 <a class="header-anchor" href="#最近学习的新技术" aria-label="Permalink to &quot;最近学习的新技术&quot;">​</a></h3><ul><li>JDK21 的虚拟线程</li><li>AIGC</li><li>K8S</li></ul><h3 id="说一下对自己的评价" tabindex="-1">说一下对自己的评价 <a class="header-anchor" href="#说一下对自己的评价" aria-label="Permalink to &quot;说一下对自己的评价&quot;">​</a></h3><p>这个问题和有什么缺点有点像，只不过要比那个更加难回答一些。在面试中回答这个问题时，最好的策略是<strong>诚实且自信</strong>。回答的方式应该是<strong>先突出你的优点，同时也可以适当地提及一些自己的不足以及后续的改进措施</strong>。</p><p>在优势方面可以从这几个方面回答：</p><ol><li><strong>专业技能</strong>：提及你在专业领域的技能和经验，尤其是那些与职位相关的。</li><li><strong>工作态度</strong>：强调你的职业态度，如责任感、诚信、团队合作精神等。</li><li><strong>学习能力</strong>：说明学习能力和适应变化的能力，特别是在不断变化的工作环境中。</li><li><strong>成就</strong>：举例说明过去的工作或学习中取得的成就。</li></ol><p>然后可以说一下自己的缺点和不足，可以参考缺点的那一篇，不过需要在说完缺点后有改进措施以及如何把它转化成优势。</p><p>例如：&quot;我认为我是一个对工作充满热情并且具有很强学习能力的人。在我的上一份工作中，我在参与到一个全新的项目时，在不了解业务背景以及技术架构的情况下，能够保质保量地完成任务，并且还能在完成自己的工作后给同时很好的起到了补位的作用。当然，我也注意到自己在公共演讲方面还有提升的空间，有的时候在人多的时候会有些紧张，为此我参加了相关培训，并努力在每次会议中进行实践。这个努力让我在最近的技术分享、各种评审中得到了积极的反馈&quot;。</p><h3 id="最牛逼的事情" tabindex="-1">最牛逼的事情 <a class="header-anchor" href="#最牛逼的事情" aria-label="Permalink to &quot;最牛逼的事情&quot;">​</a></h3><ul><li>非技术相关：跑半马、一个人在医院做了阑尾手术。</li></ul><h3 id="最近在看什么书" tabindex="-1">最近在看什么书 <a class="header-anchor" href="#最近在看什么书" aria-label="Permalink to &quot;最近在看什么书&quot;">​</a></h3><ul><li>技术：左耳听风、代码整洁之道。</li><li>非技术：曾国藩传</li></ul><h3 id="手里面有没有-offer" tabindex="-1">手里面有没有 offer <a class="header-anchor" href="#手里面有没有-offer" aria-label="Permalink to &quot;手里面有没有 offer&quot;">​</a></h3><ul><li><strong>如果一个 offer 都没有，也不要就说都没有</strong>，就可以说有几个公司还在流程中也行。要不然就可能会被认为竞争力不足。</li><li><strong>如果手上确实 offer 比较多，可以适当的给面试官排个序</strong>，或者做一些排除法，比如某家公司虽然给了 offer，但是不太想去，比如业务不喜欢、城市不匹配等等原因。</li><li><strong>顺便说一下你对当前面试的公司的重视</strong>。比如说贵司是我比较看重的一个选择，所以我会优先选择这里。</li></ul><h3 id="如何看待加班" tabindex="-1">如何看待加班 <a class="header-anchor" href="#如何看待加班" aria-label="Permalink to &quot;如何看待加班&quot;">​</a></h3><p>作为一个技术人员，我知道<strong>加班是不可避免</strong>的，并且在我以往的工作过程中，我也经常有加班的情况，我认为一些特殊情况下，比如<strong>项目紧急、大促值班的时候，通过加班的方式来确保项目的进展及质量是非常有必要的</strong>。</p><p>不过我也相信通过一些<strong>有效的时间管理，合理的任务分配及优先级管理可以减少一些加班的情况</strong>。我也在不断地通过提升自己的工作效率、沟通效率等方式让自己可以高效、并且高质量的完成工作。</p><p>其实，以往身边的一些例子也告诉我，有的时候加班完成的工作可能质量并不特别高，在工作中保持专注才能让我们高质量的完成工作。</p><p>看看是不是大家都在加班，是的话是因为什么加班？效率还是就是业务需求重。如果是效率可以考虑如何优化一下。</p><p>如果只有自己在加班，那就得看看自己是因为什么加班？比如需求评估不合理，有意想不到的情况。自己研发效率低等等，就需要针对性的训练和改进了。</p><p>当然，我不知道贵公司的文化是怎么样的，如果公司有加班的文化和政策的话，我也会积极配合，和同事们更好的合作，用最佳的方式确保项目按时、高质量如期交付。</p><h3 id="如何在团队合作中解决冲突和达成共识" tabindex="-1">如何在团队合作中解决冲突和达成共识 <a class="header-anchor" href="#如何在团队合作中解决冲突和达成共识" aria-label="Permalink to &quot;如何在团队合作中解决冲突和达成共识&quot;">​</a></h3><p>一句话：<strong>在做决策之前充分表达，在做了决策之后，坚定执行！不轻易承诺，承诺了就一定要做到。</strong></p><h3 id="你还有什么想要反问我的吗" tabindex="-1">你还有什么想要反问我的吗？ <a class="header-anchor" href="#你还有什么想要反问我的吗" aria-label="Permalink to &quot;你还有什么想要反问我的吗？&quot;">​</a></h3><p>要可以从以下几个方面问：</p><ol><li>做的业务主要是啥？团队各个端有多少人？<strong>业务的体量、招聘的目标</strong>？</li><li>主要使用的技术栈？</li><li><strong>对招聘的岗位的人员的定位？这个岗位负责的领域？</strong></li><li><strong>公司在 AI 这块用的怎么样？</strong></li><li>HR 面：<strong>晋升制度？薪酬体系。考核方式？成长性？比如是否定期有技术大会？</strong></li><li><strong>团队的组织架构，团队之间如何协作？有没有做 AI 相关的事情。是否有机会做？</strong></li></ol><h3 id="自己工作以来最大的成长是什么" tabindex="-1">自己工作以来最大的成长是什么？ <a class="header-anchor" href="#自己工作以来最大的成长是什么" aria-label="Permalink to &quot;自己工作以来最大的成长是什么？&quot;">​</a></h3><p>这个问的贼多！！！一定要好好想想。</p>',36)])])}const p=r(i,[["render",n]]);export{c as __pageData,p as default};
